import React from 'react';

import Chat from './components/Chat';
import SafetyDisclaimer from './components/SafetyDisclaimer';
import History from './components/History';
import './styles.css';

export default function App() {
  const [messages, setMessages] = useState([]);

  function handleReplay(userText, assistantText){
    // Append the replayed messages to the conversation
    setMessages(m => [...m, {role:'user', text: userText}, {role:'assistant', text: assistantText}]);
  }

  return (
    <div className="app-root">
      <header className="app-header">
        <h1>AI Medical Assistant (Demo)</h1>
      </header>
      <SafetyDisclaimer />
      <div className="app-grid">
        <main className="app-main">
          <Chat messages={messages} setMessages={setMessages} />
        </main>
        <aside className="app-side">
          <History onReplay={handleReplay} />
        </aside>
      </div>
    </div>
  );
}
